CREATE TABLE "Block" (
  "id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  "roomTypeId" INTEGER NOT NULL,
  "date" TEXT NOT NULL,
  "units" INTEGER NOT NULL DEFAULT 1,
  "reason" TEXT,
  CONSTRAINT "Block_roomTypeId_fkey" FOREIGN KEY ("roomTypeId") REFERENCES "RoomType" ("id") ON DELETE RESTRICT ON UPDATE CASCADE
);
CREATE TABLE "Booking" (
      "id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
      "propertyId" TEXT NOT NULL DEFAULT 'streatham',
      "roomTypeId" INTEGER,
      "physicalRoom" TEXT,
      "guestName" TEXT NOT NULL,
      "email" TEXT,
      "phone" TEXT,
      "checkIn" TEXT NOT NULL,
      "checkOut" TEXT NOT NULL,
      "units" INTEGER NOT NULL DEFAULT 1,
      "channel" TEXT NOT NULL,
      "channelRef" TEXT,
      "totalPrice" REAL,
      "status" TEXT NOT NULL DEFAULT 'confirmed',
      "notes" TEXT,
      "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "adults" INTEGER NOT NULL DEFAULT 1, "children" INTEGER NOT NULL DEFAULT 0, "stripeSessionId" TEXT, "stripePaymentUrl" TEXT, "stripeStatus" TEXT, "paidAt" TEXT,
      CONSTRAINT "Booking_roomTypeId_fkey" FOREIGN KEY ("roomTypeId") REFERENCES "RoomType" ("id") ON DELETE RESTRICT ON UPDATE CASCADE
    );
CREATE TABLE "CrmRecord" (
  "bookingId" INTEGER NOT NULL PRIMARY KEY,
  -- pre-stay
  "preStayCall" TEXT NOT NULL DEFAULT '',      -- '' | done | no_answer | not_reachable | message_sent | na
  "preStayDate" TEXT,
  "formSent" TEXT NOT NULL DEFAULT '',         -- '' | yes | no | na
  "formCompleted" TEXT NOT NULL DEFAULT '',
  -- in-stay (day after arrival)
  "midStayCall" TEXT NOT NULL DEFAULT '',
  "msDate" TEXT,
  "checkinRating" INTEGER,
  "cleanlinessRating" INTEGER,
  "issueFlagged" TEXT,
  "taskGiven" TEXT,
  -- post-stay
  "firstContact" TEXT NOT NULL DEFAULT '',
  "fcDate" TEXT,
  "feedback" TEXT,
  "rebookingInterest" TEXT NOT NULL DEFAULT '', -- '' | yes | maybe | no
  "directBookingOffered" TEXT NOT NULL DEFAULT '',
  "promoCodeGiven" TEXT,
  -- review chase
  "secondContact" TEXT NOT NULL DEFAULT '',
  "scDate" TEXT,
  "review" TEXT NOT NULL DEFAULT '',            -- '' | received | declined | chased
  "reviewDate" TEXT,
  "reviewScore" REAL,
  -- misc
  "issueReport" TEXT,
  "guestSentiment" TEXT NOT NULL DEFAULT '', -- '' | positive | neutral | negative
  "updatedAt" DATETIME,
  CONSTRAINT "Crm_booking_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking" ("id") ON DELETE CASCADE
);
CREATE TABLE "EmailBookingTask" (
  "id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  "kind" TEXT NOT NULL,              -- new | modified | needs_review
  "channel" TEXT NOT NULL DEFAULT 'booking.com',
  "channelRef" TEXT NOT NULL,
  "propertyId" TEXT,                 -- mapped from hotel_id when possible
  "bdcHotelId" TEXT,
  "checkInHint" TEXT,                -- from the email subject
  "extranetUrl" TEXT,                -- direct reservation-details link
  "note" TEXT,
  "status" TEXT NOT NULL DEFAULT 'pending',  -- pending | done | dismissed
  "emailDate" TEXT,
  "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "doneAt" DATETIME
);
CREATE TABLE "ExtrasRequest" (
  "id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  "bookingReference" TEXT NOT NULL,
  "bookingId" INTEGER, -- matched via Booking.channelRef; null = unmatched
  "extra" TEXT NOT NULL,
  "date" TEXT,
  "time" TEXT,
  "nights" INTEGER,
  "price" REAL,
  "sourceStatus" TEXT, -- status column from the CSV
  "taskStatus" TEXT NOT NULL DEFAULT 'pending', -- pending | in_progress | done | cancelled
  "raw" TEXT,
  "importedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE "ProcessedEmail" (
  "uid" INTEGER NOT NULL,
  "mailbox" TEXT NOT NULL DEFAULT 'INBOX',
  "messageId" TEXT,
  "subject" TEXT,
  "handledAs" TEXT,
  "processedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("mailbox", "uid")
);
CREATE TABLE "Property" (
  "id" TEXT NOT NULL PRIMARY KEY,
  "name" TEXT NOT NULL,
  "bdcHotelId" TEXT,
  "expediaHotelId" TEXT,
  "sortOrder" INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE "RateOverride" (
  "id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  "roomTypeId" INTEGER NOT NULL,
  "date" TEXT NOT NULL,
  "price" REAL NOT NULL,
  CONSTRAINT "RateOverride_roomTypeId_fkey" FOREIGN KEY ("roomTypeId") REFERENCES "RoomType" ("id") ON DELETE RESTRICT ON UPDATE CASCADE
);
CREATE TABLE "RoomType" (
  "id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  "propertyId" TEXT NOT NULL,
  "name" TEXT NOT NULL,
  "bdcRoomId" TEXT,
  "expediaName" TEXT,
  "physicalRooms" TEXT NOT NULL,
  "totalUnits" INTEGER NOT NULL,
  "basePrice" REAL NOT NULL DEFAULT 80, "expediaRoomId" TEXT, "expediaRatePlanId" TEXT,
  CONSTRAINT "RoomType_propertyId_fkey" FOREIGN KEY ("propertyId") REFERENCES "Property" ("id") ON DELETE RESTRICT ON UPDATE CASCADE
);
CREATE TABLE "Setting" (
  "key" TEXT NOT NULL PRIMARY KEY,
  "value" TEXT NOT NULL
);
CREATE TABLE "SyncJob" (
  "id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  "channel" TEXT NOT NULL,
  "roomTypeId" INTEGER NOT NULL,
  "date" TEXT NOT NULL,
  "field" TEXT NOT NULL,
  "value" TEXT NOT NULL,
  "status" TEXT NOT NULL DEFAULT 'pending',
  "note" TEXT,
  "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "doneAt" DATETIME,
  CONSTRAINT "SyncJob_roomTypeId_fkey" FOREIGN KEY ("roomTypeId") REFERENCES "RoomType" ("id") ON DELETE RESTRICT ON UPDATE CASCADE
);
CREATE UNIQUE INDEX "RateOverride_roomTypeId_date_key" ON "RateOverride"("roomTypeId", "date");
CREATE UNIQUE INDEX "Block_roomTypeId_date_key" ON "Block"("roomTypeId", "date");
CREATE UNIQUE INDEX "Extras_dedupe"
  ON "ExtrasRequest"("bookingReference", "extra", COALESCE("date",''), COALESCE("time",''));
CREATE UNIQUE INDEX "EmailTask_dedupe"
  ON "EmailBookingTask"("kind", "channelRef", COALESCE("emailDate",''));
